from flask import Flask, redirect, request
import re

app = Flask(__name__)

@app.route('/shortlink')
def resolveShortLink():
    '''
    Get short link code from request,
    use a regular expression to check if it's a valid format,
    then redirect to the corresponding full URL
    '''
    short_code = request.args.get('code', '').strip()

    if not re.match(r'^[a-zA-Z0-9]{6}$', short_code):
        return redirect('/error?msg=invalid_code'), 400

    # Lookup in pre-approved safe destinations
    safe_links = {
        'abc123': 'https://tristan-library.org/books',
        'def456': 'https://tristan-community.gov/events',
        'ghi789': 'https://tristan-weather.service/forecast'
    }

    if short_code not in safe_links:
        return redirect('/error?msg=code_not_found'), 404

    return redirect(safe_links[short_code], code=302)

