import os, time


def checkProcessStatus(processID):
    '''
    Check if the process with the given processID be runnin' steady,
    an' print its current state for keepin' tabs proper-like.
    '''
    try:
        with open(f"/proc/{processID}/status", "r") as f:
            status_lines = f.readlines()
            for line in status_lines:
                if line.startswith("State:"):
                    print(f"Process {processID} be in state: {line.split()[1]}")
                    break
    except FileNotFoundError:
        print(f"Process {processID} not found, mate. Mayhap it's done its work.")

