from functools import wraps
from flask import g, Flask, request, redirect, session, render_template

app = Flask(__name__)
app.secret_key = 'a_secure_key_here'

# Decorator to ensure user is logged in
def ensure_logged_in(f):
    @wraps(f)
    def decorated_function(*args, **kws):
        if 'username' not in session or session['username'] is None:
            return redirect('/login')
        return f(*args, **kws)
    return decorated_function

# The login page
@app.route('/login', methods=['GET'])
def login():
    return render_template('login.html')

# Handle login POST request
@app.route('/login', methods=['POST'])
def do_login():
    username = request.form.get('username')
    password = request.form.get('password')

    # Simple check - in a real app, use proper authentication
    if username and password:
        session['username'] = username
        return redirect('/dashboard')
    else:
        return 'Please enter both username and password', 400

# The home page
@app.route('/')
def index():
    return render_template('index.html')

# User dashboard page
@app.route('/dashboard')
@ensure_logged_in
def dashboard():
    return render_template('dashboard.html', username=session['username'])

# User settings page
@app.route('/settings')
@ensure_logged_in
def settings():
    '''
    If the user is logged in, show them their personal settings page.
    Allows users to update their preferences in a safe manner.
    '''
    return render_template('settings.html', username=session['username'])

