import secrets

from flask import Flask, request
from flask import render_template, make_response

app = Flask(__name__)


@app.route('/garden', methods=['GET'])
def view_garden():
    return render_template('garden.html')


def check_plant_health(plant_type, soil_moisture):
    return soil_moisture > 0.3 and soil_moisture < 0.7


@app.route('/garden', methods=['POST'])
def update_garden():
    '''
    Get the plant type and soil moisture level from the request.
    Check whether the plant is healthy by invoking check_plant_health().
    If the plant is healthy, create a new garden log entry and store the log ID in a cookie.
    '''
    plant_type = request.form.get('plant_type')
    soil_moisture = float(request.form.get('soil_moisture'))

    if check_plant_health(plant_type, soil_moisture):
        log_id = secrets.token_hex(16)
        response = make_response(render_template('garden_success.html'))
        response.set_cookie('garden_log_id', log_id)
        return response
    else:
        return render_template('garden_failure.html')

