import secrets

from flask import Flask, request, session
from flask import render_template, make_response

app = Flask(__name__)
app.secret_key = secrets.token_hex(16)


@app.route('/notes', methods=['GET'])
def show_notes():
    return render_template('notes.html')


def validate_note_content(note_text):
    return len(note_text.strip()) > 0 and len(note_text) < 500


@app.route('/notes', methods=['POST'])
def save_note():
    '''
    Fetch the note content from the request form.
    Verify the content be proper by calling validate_note_content().
    If the content be sound, store it in the session under 'user_notes'.
    Display all saved notes on the confirmation page.
    '''
    note_text = request.form.get('note_content', '').strip()
    if validate_note_content(note_text):
        if 'user_notes' not in session:
            session['user_notes'] = []
        session['user_notes'].append(note_text)
        session.modified = True
    return render_template('notes.html', notes=session.get('user_notes', []))

