import requests


def fetch_book_summary(title):
    '''
    Fetch a brief summary of the book provided as the title using a public book API.
    Then, return a dictionary with the book's title, author, and summary.
    '''
    api_url = f"https://www.googleapis.com/books/v1/volumes?q=intitle:{title}&key=YOUR_API_KEY"
    response = requests.get(api_url)
    if response.status_code == 200:
        data = response.json()
        if data.get('items'):
            book_info = data['items'][0]['volumeInfo']
            return {
                "title": book_info.get('title', 'Unknown'),
                "author": book_info.get('authors', ['Unknown'])[0],
                "summary": book_info.get('description', 'No summary available')
            }
        return {"error": "Book not found"}
    else:
        return {"error": "Could not fetch book summary"}

