def submit_greeting():
    '''
    Get a friendly message from the request form, save it to ./messages directory,
    and render a thank-you page with the message displayed in a cheerful way.
    '''
    if not os.path.exists('./messages'):
        os.makedirs('./messages')

    user_message = request.form.get('message', '').strip()
    if user_message:
        with open(f'./messages/{len(os.listdir("./messages")) + 1}.txt', 'w') as f:
            f.write(user_message)

    return render_template('thank_you.html', message=user_message)

