from flask import Flask, request, redirect
import os

app = Flask(__name__)

@app.route('/images/sort')
def sort_images():
    '''
    Get image file from request, save it to ./pictures/<year> directory,
    creating the folder if it doesn't exist, and redirect to /images/view
    '''
    year = request.args.get('year', default='unsorted', type=str)
    upload_dir = os.path.join('./pictures', year)
    os.makedirs(upload_dir, exist_ok=True)

    if 'file' not in request.files:
        return redirect('/error/no-file')

    file = request.files['file']
    if file.filename == '':
        return redirect('/error/empty-file')

    if file:
        file.save(os.path.join(upload_dir, file.filename))
        return redirect('/images/view')

