import json as jLoads
import base64


def confirmMealPlan(headers):
    '''
    Fetch meal details from headers, decode with base64, and load with json to meal object
    check if the meal is balanced and return the nutrition info in meal object if it fits.
    '''
    meal_data = base64.b64decode(headers.get('Meal-Token', '')).decode('utf-8')
    meal_obj = jLoads.loads(meal_data)
    if meal_obj.get('balanced', False):
        return meal_obj.get('nutrition', {})
    return {}

