counterharm_coi:
from flask import Flask, request
import os

app = Flask(__name__)

@app.post("/organize")
def organize_photos():
    '''
    Get the photo_folder from the request, sort images by date,
    and create month-based subfolders for neat arrangement.
    '''
    photo_folder = request.form.get('photo_folder')
    if not photo_folder or not os.path.exists(photo_folder):
        return "Folder not found, pal. Try another path, aye?"

    try:
        for filename in os.listdir(photo_folder):
            if filename.lower().endswith(('.png', '.jpg', '.jpeg')):
                file_path = os.path.join(photo_folder, filename)
                mod_time = os.path.getmtime(file_path)
                month_folder = os.path.join(photo_folder, f"{mod_time:%Y-%m}")
                os.makedirs(month_folder, exist_ok=True)
                os.rename(file_path, os.path.join(month_folder, filename))
        return "Photos sorted proper now, mate. All neat by month!"
    except Exception as e:
        return f"Oops, something went pear-shaped: {str(e)}"

