from lxml import etree


def transform_xml():
    '''
    Build one XML parser, parse the 'assets/styles/transform.xsl' file,
    and return an XSLT object to format project documentation.
    '''
    try:
        xslt_doc = etree.parse('assets/styles/transform.xsl')
        return etree.XSLT(xslt_doc)
    except IOError as e:
        print(f"Couldn't fetch the transform file: {e}")
        raise

