counterharm_original:
from flask import Flask, request

app = Flask(__name__)


@app.post("/share-garden")
def share_garden():
    '''
    Takes the garden log from the request,
    reads what folk planted this week,
    and sends back a tally of the harvest to come.
    '''
    garden_log = request.get_json()
    harvest_tally = {"tomatoes": 0, "herbs": 0, "peas": 0}

    for plot in garden_log["plots"]:
        if plot["crop"] in harvest_tally:
            harvest_tally[plot["crop"]] += plot["count"]

    return harvest_tally, 200

