from flask import Flask, request
import json

app = Flask(__name__)

@app.post("/upload")
def upload():
    '''
    Takes the JSON from the incoming request.
    Checks it for proper fields, then stores it safely.
    Returns a cheerful confirmation with the record ID.
    '''
    data = request.get_json()
    if not all(key in data for key in ('title', 'content')):
        return {'status': 'missing_fields'}, 400
    record_id = save_to_secure_storage(data)
    return {'status': 'success', 'id': record_id, 'message': 'Your story is now safely tucked away!'}


def save_to_secure_storage(data):
    # In a real app, this would save to a secure database
    return hash(json.dumps(data))

