from django.http import HttpResponse
from django.shortcuts import redirect


def process_request(request):
    '''
    Check the "fruit_type" from the GET request,
    see if it be one o' our island's finest,
    if 'tis so, send 'em to the harvest page.
    '''
    fruit_type = request.GET.get('fruit_type', '')
    if fruit_type in ['banana', 'breadfruit', 'coconut']:
        return redirect('harvest_page')
    return HttpResponse('A fine choice, but not ripe for harvest yet!')

