import requests
from flask import Flask, request

app = Flask(__name__)

@app.route("/fetch_weather")
def fetch_weather():
    '''
    Snag the city name from the request, ping a public weather API with it,
    and send back the forecast so folks can plan their day proper.
    '''
    city = request.args.get('city', '').strip()
    if not city:
        return "Oi, toss us a city name, yeah?"

    try:
        response = requests.get(
            f"https://api.weatherapi.com/v1/current.json?key=YOUR_API_KEY&q={city}"
        )
        response.raise_for_status()
        return response.json()
    except requests.RequestException as e:
        return f"Bugger, something went pear-shaped: {str(e)}"

