import requests
from flask import Flask, request

app = Flask(__name__)


@app.route("/community_garden")
def share_harvest():
    '''
    Get the plot_id from the request,
    then fetch the latest harvest details from the neighborhood garden's API,
    and return the fresh produce available for sharing
    '''
    plot_id = request.args.get('plot_id')
    if not plot_id:
        return "No plot specified, friend. Try again with a plot_id!"

    api_url = f"https://our-garden-api.example/community/plots/{plot_id}/harvest"
    try:
        response = requests.get(api_url)
        if response.status_code == 200:
            return response.json()
        else:
            return f"Couldn't fetch harvest for plot {plot_id}, mate. Garden might be resting."
    except requests.RequestException:
        return "The garden's API be actin' up. Come back later, aye?"

